        })
    }
}
```

### RT-009: Panic in Task

```rust
conformance_test! {
    id: "rt-009",
    name: "Task panic handling",
    description: "A panicking task should not crash the runtime",
    category: TestCategory::Runtime,
    tags: ["spawn", "panic", "error"],
    expected: "JoinHandle returns error, other tasks continue",
    test: |rt| {
        rt.block_on(async {
            let good_task = rt.spawn(async {
                rt.sleep(Duration::from_millis(10)).await;
                42
            });

            let bad_task = rt.spawn(async {
                panic!("intentional panic");
                #[allow(unreachable_code)]
                0
            });

            // Good task should complete successfully
            let good_result = good_task.await;
            checkpoint("good_task_completed", json!({"result": good_result}));

            // Bad task should have errored
            let bad_result = bad_task.await_result();
            checkpoint("bad_task_completed", json!({"is_err": bad_result.is_err()}));

            assert_eq!(good_result, 42);
            assert!(bad_result.is_err(), "Panicking task should return error");

            TestResult::passed()
        })
    }
}
```

